   102→  /** Class representing a binding in CBV evaluation. */ 
   103→  static class ValueBinding extends Binding {
   104→    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
   105→    public JamVal value() { 
   106→      if (value == null) illegalForwardReference(var());
   107→      return value; 
   108→    }
   109→    public void setBinding(Suspension s) { value = s.eval(); }  // immediate evaluation
   110→    public String toString() { return "[" + var + ", " + value + "]"; }
   111→  }
   112→  
   113→  /** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
   114→  static class NameBinding extends Binding {
   115→    protected Suspension susp;
   116→    NameBinding(Variable v, Suspension s) { 
   117→      super(v,null);
   118→      susp = s;
   119→    }
   120→    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
   121→    public void setBinding(Suspension s) { susp = s; }
   122→    public String toString() { return "[" + var + ", " + susp + "]"; }
   123→  }
   124→  
   125→ /** Class representing a binding in CBNeed evaluation.  The inherited value field is used to hold the value
   126→    * first computed by need .. */
   127→  static class NeedBinding extends NameBinding {
   128→    NeedBinding(Variable v, Suspension s) { super(v,s); }
   129→    public JamVal value() {
   130→      if (value == null) {  // a legitimate JamVal CANNOT be null
   131→        if (susp == null) illegalForwardReference(var());
   132→        else {             // Force the suspension and cache its value
   133→          value = susp.eval();
   134→          susp = null;     // release susp object for GC!
   135→        }
   136→      }
   137→      return value;
   138→    }
   139→    public void setBinding(AST exp, EvalVisitor ev) { susp = new ConcreteSuspension(exp, ev); value = null; }
   140→    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
   141→  }
   142→  
   143→  /** Helper method supporting Binding classes */
   144→  static JamVal illegalForwardReference(Variable v) {
   145→    throw new EvalException("Attempt to evaluate variable " + v + " bound to null, indicating an illegal forward reference");
   146→  }
