/** Class representing a binding in CBName evaluation. The inherited value field is ignored. */
static class NameBinding extends Binding {
  protected Suspension susp;
  /** Flag to detect re-entrant evaluation (illegal forward references in recursive let). */
  protected boolean evaluating = false;
  NameBinding(Variable v, Suspension s) {
    super(v,null);
    susp = s;
  }
  public JamVal value() {
    if (susp == null) return illegalForwardReference(var());
    if (evaluating) return illegalForwardReference(var());
    evaluating = true;
    try {
      return susp.eval();
    } finally {
      evaluating = false;
    }
  }
  public void setBinding(Suspension s) { susp = s; evaluating = false; }
  public String toString() { return "[" + var + ", " + susp + "]"; }
}

