/** Class for a lazy cons structure using call-by-name semantics. Re-evaluates suspensions on each access. */
static class JamLazyNameCons extends JamCons {
  /** Suspension for first */
  protected Suspension firstSusp;
  /** Suspension for rest */
  protected Suspension restSusp;

  public JamLazyNameCons(Suspension fs, Suspension rs) {
    super(null, null);
    firstSusp = fs;
    restSusp = rs;
  }

  /** Evaluates the first suspension each time (call-by-name). */
  public JamVal first() { return firstSusp.eval(); }

  /** Evaluates the rest suspension each time (call-by-name) and checks it is a list. */
  public JamList rest() { return JamCons.checkList(restSusp.eval()); }

  /** Short-circuit equality: uses identity checks on rest to handle infinite lazy lists. */
  public boolean equals(Object other) {
    if (this == other) return true;
    if (other == null || !(other instanceof JamCons)) return false;
    JamCons otherCons = (JamCons) other;
    if (!first().equals(otherCons.first())) return false;
    JamList myRest = rest();
    JamList otherRest = otherCons.rest();
    if (myRest == otherRest) return true;
    return myRest.equals(otherRest);
  }
}

/** Class for a lazy cons with call-by-need optimization. Caches evaluated suspensions. */
static class JamLazyNeedCons extends JamLazyNameCons {

  public JamLazyNeedCons(Suspension fs, Suspension rs) { super(fs, rs); }

  /** Evaluates the first suspension once and caches the result. */
  public JamVal first() {
    if (firstSusp != null) {
      first = firstSusp.eval();
      firstSusp = null;
    }
    return first;
  }

  /** Evaluates the rest suspension once, checks it is a list, and caches the result. */
  public JamList rest() {
    if (restSusp != null) {
      rest = JamCons.checkList(restSusp.eval());
      restSusp = null;
    }
    return (JamList) rest;
  }
}

