import junit.framework.TestCase;
import java.io.*;

/** Agent tests for Assignment 3: Lazy Evaluation and Recursive Definitions. */
public class AgentTest extends TestCase {

  public AgentTest(String name) { super(name); }

  /* Helper methods for all 9 evaluation modes */

  private void valueValueCheck(String name, String answer, String program) {
    assertEquals("VV " + name, answer, new Interpreter(new StringReader(program)).valueValue().toString());
  }
  private void valueNameCheck(String name, String answer, String program) {
    assertEquals("VN " + name, answer, new Interpreter(new StringReader(program)).valueName().toString());
  }
  private void valueNeedCheck(String name, String answer, String program) {
    assertEquals("VNd " + name, answer, new Interpreter(new StringReader(program)).valueNeed().toString());
  }
  private void nameValueCheck(String name, String answer, String program) {
    assertEquals("NV " + name, answer, new Interpreter(new StringReader(program)).nameValue().toString());
  }
  private void nameNameCheck(String name, String answer, String program) {
    assertEquals("NN " + name, answer, new Interpreter(new StringReader(program)).nameName().toString());
  }
  private void nameNeedCheck(String name, String answer, String program) {
    assertEquals("NNd " + name, answer, new Interpreter(new StringReader(program)).nameNeed().toString());
  }
  private void needValueCheck(String name, String answer, String program) {
    assertEquals("NdV " + name, answer, new Interpreter(new StringReader(program)).needValue().toString());
  }
  private void needNameCheck(String name, String answer, String program) {
    assertEquals("NdN " + name, answer, new Interpreter(new StringReader(program)).needName().toString());
  }
  private void needNeedCheck(String name, String answer, String program) {
    assertEquals("NdNd " + name, answer, new Interpreter(new StringReader(program)).needNeed().toString());
  }

  private void allCheck(String name, String answer, String program) {
    valueValueCheck(name, answer, program);
    valueNameCheck(name, answer, program);
    valueNeedCheck(name, answer, program);
    nameValueCheck(name, answer, program);
    nameNameCheck(name, answer, program);
    nameNeedCheck(name, answer, program);
    needValueCheck(name, answer, program);
    needNameCheck(name, answer, program);
    needNeedCheck(name, answer, program);
  }

  private void lazyCheck(String name, String answer, String program) {
    valueNameCheck(name, answer, program);
    valueNeedCheck(name, answer, program);
    nameNameCheck(name, answer, program);
    nameNeedCheck(name, answer, program);
    needNameCheck(name, answer, program);
    needNeedCheck(name, answer, program);
  }

  /* ========== Context-Sensitive Checking Tests ========== */

  /** Test duplicate parameters in map throw SyntaxException. */
  public void testDuplicateMapParams() {
    try {
      new Interpreter(new StringReader("map x, x to x"));
      fail("Expected SyntaxException for duplicate map params");
    } catch (SyntaxException e) { /* expected */ }
  }

  /** Test duplicate variables in let throw SyntaxException. */
  public void testDuplicateLetVars() {
    try {
      new Interpreter(new StringReader("let x := 1; x := 2; in x"));
      fail("Expected SyntaxException for duplicate let vars");
    } catch (SyntaxException e) { /* expected */ }
  }

  /** Test free variable throws SyntaxException. */
  public void testFreeVariable() {
    try {
      new Interpreter(new StringReader("x + 3"));
      fail("Expected SyntaxException for free variable");
    } catch (SyntaxException e) { /* expected */ }
  }

  /** Test free variable inside map body throws SyntaxException. */
  public void testFreeVarInMapBody() {
    try {
      new Interpreter(new StringReader("map x to y"));
      fail("Expected SyntaxException for free variable in map body");
    } catch (SyntaxException e) { /* expected */ }
  }

  /** Test variable bound in map is not free. */
  public void testBoundVarInMap() {
    allCheck("boundVar", "5", "let f := map x to x; in f(5)");
  }

  /* ========== Recursive Let Tests ========== */

  /** Test simple recursive function (factorial). */
  public void testRecursiveFactorial() {
    String input = "let fact := map n to if n = 0 then 1 else n * fact(n - 1); in fact(6)";
    allCheck("recursiveFactorial", "720", input);
  }

  /** Test mutually recursive definitions. */
  public void testMutualRecursion() {
    String input =
      "let even := map n to if n = 0 then true else odd(n - 1); " +
      "    odd  := map n to if n = 0 then false else even(n - 1); " +
      "in even(10)";
    allCheck("mutualRecursion", "true", input);
  }

  /** Test recursive append (from instructions). */
  public void testRecursiveAppend() {
    String input =
      "let append := map x,y to if empty?(x) then y else cons(first(x), append(rest(x), y)); " +
      "    l := cons(1, cons(2, cons(3, empty))); " +
      "in append(l, l)";
    allCheck("recursiveAppend", "(1 2 3 1 2 3)", input);
  }

  /** Test forward reference in recursive let (value binding) throws EvalException. */
  public void testForwardRefValue() {
    try {
      String input = "let a := a; in a";
      new Interpreter(new StringReader(input)).valueValue();
      fail("Expected EvalException for forward reference in CBV");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test forward reference in recursive let with CBName throws EvalException. */
  public void testForwardRefName() {
    try {
      String input = "let a := a; in a";
      new Interpreter(new StringReader(input)).nameName();
      fail("Expected EvalException for forward reference in CBName");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test forward reference in recursive let with CBNeed throws EvalException. */
  public void testForwardRefNeed() {
    try {
      String input = "let a := a; in a";
      new Interpreter(new StringReader(input)).needNeed();
      fail("Expected EvalException for forward reference in CBNeed");
    } catch (EvalException e) { /* expected */ }
  }

  /* ========== Lazy Cons Tests ========== */

  /** Test infinite stream of ones. */
  public void testInfiniteOnes() {
    String input = "let ones := cons(1, ones); in first(ones)";
    lazyCheck("infiniteOnes", "1", input);
  }

  /** Test rest of infinite stream. */
  public void testInfiniteOnesRest() {
    String input = "let ones := cons(1, ones); in first(rest(rest(ones)))";
    lazyCheck("infiniteOnesRest", "1", input);
  }

  /** Test lazy cons with non-list second arg - doesn't error until rest() is called. */
  public void testLazyConsNonListRest() {
    String input = "let p := cons(1, 2); in first(p)";
    lazyCheck("lazyConsNonListFirst", "1", input);
  }

  /** Test lazy cons with non-list second arg - errors on rest(). */
  public void testLazyConsNonListRestError() {
    try {
      String input = "let p := cons(1, 2); in rest(p)";
      new Interpreter(new StringReader(input)).valueName();
      fail("Expected EvalException for non-list rest");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test cons? on lazy cons returns true. */
  public void testConsPredicateLazy() {
    String input = "let ones := cons(1, ones); in cons?(ones)";
    lazyCheck("consPredicateLazy", "true", input);
  }

  /** Test list? on lazy cons returns true. */
  public void testListPredicateLazy() {
    String input = "let ones := cons(1, ones); in list?(ones)";
    lazyCheck("listPredicateLazy", "true", input);
  }

  /* ========== Short-Circuit Lazy Equality Tests ========== */

  /** Test short-circuit equality with different first elements. */
  public void testLazyEqualsDiffFirst() {
    String input = "let xs := cons(1, xs); ys := cons(2, ys); in xs = ys";
    lazyCheck("lazyEqualsDiffFirst", "false", input);
  }

  /** Test short-circuit not-equals with different first elements. */
  public void testLazyNotEqualsDiffFirst() {
    String input = "let xs := cons(1, xs); ys := cons(2, ys); in xs != ys";
    lazyCheck("lazyNotEqualsDiffFirst", "true", input);
  }

  /* ========== Safety / Type Checking Tests ========== */

  /** Test type error: applying non-function. */
  public void testApplyNonFunction() {
    try {
      allCheck("applyNonFunction", "err", "5(3)");
      fail("Expected EvalException for applying non-function");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test type error: if with non-boolean test. */
  public void testIfNonBoolean() {
    try {
      allCheck("ifNonBoolean", "err", "if 1 then 2 else 3");
      fail("Expected EvalException for non-boolean if test");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test type error: unary minus on boolean. */
  public void testUnaryMinusOnBool() {
    try {
      allCheck("unaryMinusOnBool", "err", "- true");
      fail("Expected EvalException for unary minus on boolean");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test type error: tilde on integer. */
  public void testTildeOnInt() {
    try {
      allCheck("tildeOnInt", "err", "~ 5");
      fail("Expected EvalException for tilde on integer");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test division by zero. */
  public void testDivByZero() {
    try {
      allCheck("divByZero", "err", "10 / 0");
      fail("Expected EvalException for division by zero");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test wrong arity application. */
  public void testWrongArity() {
    try {
      allCheck("wrongArity", "err", "(map x to x)(1, 2)");
      fail("Expected EvalException for wrong arity");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test cons with wrong number of arguments. */
  public void testConsWrongArity() {
    try {
      allCheck("consWrongArity", "err", "cons(1)");
      fail("Expected EvalException for cons with 1 arg");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test first on non-cons. */
  public void testFirstOnNonCons() {
    try {
      allCheck("firstOnNonCons", "err", "first(empty)");
      fail("Expected EvalException for first on empty");
    } catch (EvalException e) { /* expected */ }
  }

  /** Test rest on non-cons. */
  public void testRestOnNonCons() {
    try {
      allCheck("restOnNonCons", "err", "rest(empty)");
      fail("Expected EvalException for rest on empty");
    } catch (EvalException e) { /* expected */ }
  }

  /* ========== Misc Tests ========== */

  /** Test nested let with recursion. */
  public void testNestedLetRecursion() {
    String input =
      "let f := map n to if n = 0 then 1 else n * f(n - 1); " +
      "in let g := map n to f(n) + f(n - 1); " +
      "   in g(5)";
    allCheck("nestedLetRecursion", "144", input);
  }

  /** Test recursive list operations: length function. */
  public void testRecursiveLength() {
    String input =
      "let length := map lst to if empty?(lst) then 0 else 1 + length(rest(lst)); " +
      "in length(cons(1, cons(2, cons(3, empty))))";
    allCheck("recursiveLength", "3", input);
  }
}

